"use client"

import axios from "axios";
import { useRouter } from "next/navigation";
import React, { useState } from "react";
import { Form, Button, Container, Row, Col } from "react-bootstrap";

const VerifyPage = () => {
  const [otp, setOtp] = useState("");
    const email = localStorage.getItem("email");

  const router = useRouter();

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    if (/^\d{0,4}$/.test(value)) {
      setOtp(value);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (otp.length === 4) {
      console.log("OTP Verified:", otp);

      axios.post("/api/verify-otp", { email, otp }).then((res) => {
        console.log(res.data);

        if(res.data.message == "success"){
          localStorage.setItem("user", JSON.stringify(res.data.user));
          alert("OTP Verified Successfully");

          axios.post("/api/offer-letter", { email }).then((res) => {
            console.log(res.data);
            router.push("/dashboard");

          }).catch((err) => {
            console.error(err);
          });

        }else{
          alert("Invalid OTP. Please try again.");
        }
      }).catch((err) => {
        console.error(err);
      })  


    } else {
      alert("Please enter a valid 4-digit OTP.");
    }
  };

  const resendOtpHandler = () => {
    axios.post("/api/resend-otp", { email }).then((res) => {
      console.log(res.data);
      if(res.data.message == "success"){
        alert("OTP resent successfully");
      }else{
        alert("Email not registered");
      }
    }).catch((err) => {
      console.error(err);
    })
  }

  return (
    <Container
      className="d-flex justify-content-center align-items-center"
      style={{ height: "100vh" }}
    >
      <Row className="w-100 justify-content-center">
        <Col md={6}>
          <h2 className="text-center mb-4">Verify OTP</h2>
          <Form onSubmit={handleSubmit}>
            <Form.Group className="mb-3" controlId="formOtp">
              <Form.Label>Enter OTP</Form.Label>
              <Form.Control
                type="text"
                value={otp}
                onChange={handleChange}
                placeholder="Enter 4-digit OTP"
                maxLength={4}
              />
            </Form.Group>
            <div onClick={resendOtpHandler} className="d-flex justify-content-center w-100 text-primary pb-2 cursor-pointer">Resend Otp</div>
            <Button variant="primary" type="submit" className="w-100">
              Verify
            </Button>
          </Form>
        </Col>
      </Row>
    </Container>
  );
};

export default VerifyPage;
